export const handle = async (request, response) => {
    let odataEntityId = null;
    let guid = null;

    try {
        const raw = request.inputs.httpResponseHeaders;
        let headers = null;

        if (typeof raw === "string") {
            headers = JSON.parse(raw);
        } else if (raw && typeof raw === "object") {
            headers = raw;
        }

        if (headers) {
            odataEntityId = headers["OData-EntityId"]?.[0] || headers["Location"]?.[0] || null;

            if (odataEntityId) {
                const match = odataEntityId.match(/\(([^)]+)\)/);
                guid = match ? match[1] : null;
            }
        }
    } catch (e) {
        odataEntityId = null;
        guid = null;
    }

    response.data = {
        odataEntityId,
        guid
    };

    return response;
}
